package ccxtprediction

import ccxt "github.com/ccxt/ccxt/go/v4"

type Myriad struct {
	*MyriadCore
	Core          *MyriadCore
	exchangeTyped *ccxt.BaseExchangeTyped
}

func NewMyriad(userConfig map[string]any) *Myriad {
	p := NewMyriadCore()
	p.Init(userConfig)
	return &Myriad{
		MyriadCore:    p,
		Core:          p,
		exchangeTyped: ccxt.NewBaseExchangeTyped(&p.BaseExchange),
	}
}
func NewMyriadFromCore(core *MyriadCore) *Myriad {
	return &Myriad{
		MyriadCore:    core,
		Core:          core,
		exchangeTyped: ccxt.NewBaseExchangeTyped(&core.BaseExchange),
	}
}

